/**
 * The registry-driven generic proxy — the north-star primitive (docs §17).
 *
 * One generic call covers every own-tier provider: resolve the API base URL and
 * auth-header template from the registry, inject the raw credential the
 * maintainer holds, call the provider's *real* API, return the raw response. No
 * per-integration client code — that is how a registry scales to hundreds of
 * providers (Nango runs 800+ on exactly this).
 *
 *   connect("bird", env).get("/workspaces")
 *   connect("wordpress", env).post("/sites/x/posts", { title })
 *
 * Three clean concerns compose here (docs §17.3):
 *   • which credential        → the maintainer, via ctx.token()
 *   • where the API is + auth  → the registry, via proxyConfig(service)
 *   • making the call          → this module
 *
 * Own tier only. Composio-masked providers expose no injectable credential, so
 * they stay on execute (connect().run() / searchActions, docs §16) — the proxy
 * has nothing to inject and says so.
 */

import { proxyConfig, type ProxyConfig } from "@clawnify/integrations";
import type { AccessContext } from "@clawnify/integrations";

export type HttpMethod = "GET" | "POST" | "PUT" | "PATCH" | "DELETE";

/** Per-call options for the low-level {@link ProxyClient.request}. */
export interface ProxyRequestOpts {
  method?: HttpMethod;
  /** Path appended to the registry base URL, e.g. "/workspaces". */
  endpoint: string;
  /** Query params; undefined values are skipped. */
  query?: Record<string, string | number | boolean | undefined>;
  /** Request body. Plain objects are JSON-encoded; strings/buffers pass through. */
  body?: unknown;
  /** Extra headers, merged over the resolved auth headers. */
  headers?: Record<string, string>;
  /**
   * Values for `${connectionConfig.x}` templates in the base URL (e.g. Bird's
   * `subdomain`). Falls back to env `${SERVICE}_${KEY}` (e.g. BIRD_SUBDOMAIN).
   */
  connectionConfig?: Record<string, string>;
}

/** Raw outcome of a proxy request — never throws on HTTP status. */
export interface ProxyResult {
  status: number;
  headers: Headers;
  /** Parsed JSON when the response is JSON, else the raw text. */
  data: unknown;
}

/**
 * Generic provider-API client. The convenience verbs return parsed data and
 * throw on a non-2xx status; `request()` is the escape hatch that returns the
 * full {@link ProxyResult} and never throws on status.
 */
export interface ProxyClient {
  get(endpoint: string, opts?: Omit<ProxyRequestOpts, "method" | "endpoint" | "body">): Promise<unknown>;
  post(endpoint: string, body?: unknown, opts?: Omit<ProxyRequestOpts, "method" | "endpoint" | "body">): Promise<unknown>;
  put(endpoint: string, body?: unknown, opts?: Omit<ProxyRequestOpts, "method" | "endpoint" | "body">): Promise<unknown>;
  patch(endpoint: string, body?: unknown, opts?: Omit<ProxyRequestOpts, "method" | "endpoint" | "body">): Promise<unknown>;
  delete(endpoint: string, opts?: Omit<ProxyRequestOpts, "method" | "endpoint" | "body">): Promise<unknown>;
  /** Low-level call returning status + headers + data; throws only on network / unresolved-template errors. */
  request(opts: ProxyRequestOpts): Promise<ProxyResult>;
}

const TEMPLATE_RE = /\$\{([^}]+)\}/g;

/** Auth modes that carry a bearer credential when a provider declares no header template. */
const BEARER_MODES = new Set(["OAUTH2", "OAUTH2_CC", "OAUTH1", "JWT"]);

interface TemplateVars {
  accessToken: string | null;
  apiKey: string | null;
  connectionConfig: Record<string, string>;
}

/** Substitute `${accessToken}` / `${apiKey}` / `${connectionConfig.x}`; throws on an unresolved var. */
function fillTemplate(tpl: string, vars: TemplateVars, where: string): string {
  return tpl.replace(TEMPLATE_RE, (_m, expr: string) => {
    const key = expr.trim();
    if (key === "accessToken") {
      if (vars.accessToken == null) throw new Error(`${where}: no access token to fill \${accessToken}`);
      return vars.accessToken;
    }
    if (key === "apiKey") {
      if (vars.apiKey == null) throw new Error(`${where}: no api key to fill \${apiKey}`);
      return vars.apiKey;
    }
    if (key.startsWith("connectionConfig.")) {
      const field = key.slice("connectionConfig.".length);
      const v = vars.connectionConfig[field];
      if (v == null || v === "") {
        throw new Error(
          `${where}: missing connectionConfig "${field}" — pass it in opts.connectionConfig or set env ${field.toUpperCase()}`,
        );
      }
      return v;
    }
    throw new Error(`${where}: unsupported template variable \${${key}}`);
  });
}

/** Resolve a proxy request to a concrete fetch input. Pure — no network. */
export function resolveRequest(
  service: string,
  cfg: ProxyConfig,
  token: string | null,
  env: Record<string, string | undefined>,
  opts: ProxyRequestOpts,
): { url: string; method: HttpMethod; headers: Record<string, string>; body: BodyInit | undefined } {
  if (!cfg.baseUrl) throw new Error(`"${service}" has no base URL in the connections registry`);

  // connectionConfig values, resolved per var as: per-call override → env
  // (${SERVICE}_${KEY}) → registry default_value (providers.yaml). For Bird the
  // registry default supplies subdomain="api", so the base URL builds without the
  // app knowing it; a per-call/env value still wins (e.g. a media/email host).
  const connectionConfig: Record<string, string> = {};
  for (const [k, v] of Object.entries(opts.connectionConfig ?? {})) {
    if (typeof v === "string") connectionConfig[k] = v;
  }
  const cfgVarRe = /\$\{connectionConfig\.([^}]+)\}/g;
  for (const tpl of [cfg.baseUrl, ...Object.values(cfg.proxyHeaders ?? {})]) {
    for (const m of tpl.matchAll(cfgVarRe)) {
      const field = m[1].trim();
      if (connectionConfig[field] != null) continue;
      const fromEnv = env[`${service.toUpperCase().replace(/-/g, "_")}_${field.toUpperCase()}`];
      if (typeof fromEnv === "string" && fromEnv) {
        connectionConfig[field] = fromEnv;
        continue;
      }
      const fromDefault = cfg.connectionConfigDefaults?.[field];
      if (typeof fromDefault === "string" && fromDefault) connectionConfig[field] = fromDefault;
    }
  }

  const vars: TemplateVars = { accessToken: token, apiKey: token, connectionConfig };

  const base = fillTemplate(cfg.baseUrl, vars, `${service} base URL`).replace(/\/+$/, "");
  const path = opts.endpoint.startsWith("/") ? opts.endpoint : `/${opts.endpoint}`;
  let url = base + path;
  if (opts.query) {
    const qs = new URLSearchParams();
    for (const [k, v] of Object.entries(opts.query)) if (v !== undefined) qs.set(k, String(v));
    const s = qs.toString();
    if (s) url += (url.includes("?") ? "&" : "?") + s;
  }

  // Auth headers: explicit template, else a Bearer default for token-bearing modes.
  const headers: Record<string, string> = {};
  if (cfg.proxyHeaders && Object.keys(cfg.proxyHeaders).length) {
    for (const [name, tpl] of Object.entries(cfg.proxyHeaders)) {
      headers[name] = fillTemplate(tpl, vars, `${service} header "${name}"`);
    }
  } else if (token && BEARER_MODES.has(cfg.authMode)) {
    headers["authorization"] = `Bearer ${token}`;
  }

  // Body encoding: plain objects → JSON; strings/buffers pass through untouched.
  let body: BodyInit | undefined;
  if (opts.body !== undefined && opts.body !== null) {
    if (typeof opts.body === "string" || opts.body instanceof Uint8Array || opts.body instanceof ArrayBuffer) {
      body = opts.body as BodyInit;
    } else {
      body = JSON.stringify(opts.body);
      if (!Object.keys(headers).some((h) => h.toLowerCase() === "content-type")) {
        headers["content-type"] = "application/json";
      }
    }
  }

  for (const [k, v] of Object.entries(opts.headers ?? {})) headers[k] = v;

  return { url, method: opts.method ?? "GET", headers, body };
}

async function parseResponse(res: Response): Promise<unknown> {
  const ct = res.headers.get("content-type") ?? "";
  const text = await res.text();
  if (!text) return null;
  if (ct.includes("application/json") || ct.includes("+json")) {
    try {
      return JSON.parse(text);
    } catch {
      return text;
    }
  }
  return text;
}

/**
 * Build the generic proxy client for an own-tier service. `service` is the
 * registry id (`bird`, `wordpress`, …); the maintainer behind ctx supplies the
 * credential. Returns null when the service isn't in the proxy registry — the
 * caller keeps the execute path (connect().run()) for managed/Composio
 * integrations, which the proxy can't serve (no injectable credential).
 */
export function makeProxyClient(service: string, ctx: AccessContext): ProxyClient | null {
  const cfg = proxyConfig(service);
  if (!cfg) return null;

  async function request(opts: ProxyRequestOpts): Promise<ProxyResult> {
    const token = await ctx.token();
    if (token == null && cfg!.authMode !== "NONE") {
      throw new Error(
        `"${service}" has no usable credential for a direct API call. If it's a managed/Composio integration, ` +
          `use connect("${service}").run(action, body) (find the action via searchActions).`,
      );
    }
    const { url, method, headers, body } = resolveRequest(service, cfg!, token, ctx.env, opts);
    const res = await fetch(url, { method, headers, body });
    return { status: res.status, headers: res.headers, data: await parseResponse(res) };
  }

  async function send(
    method: HttpMethod,
    endpoint: string,
    opts: Omit<ProxyRequestOpts, "method" | "endpoint">,
  ): Promise<unknown> {
    const r = await request({ ...opts, method, endpoint });
    if (r.status < 200 || r.status >= 300) {
      const snippet = typeof r.data === "string" ? r.data : JSON.stringify(r.data);
      throw new Error(`${service} ${method} ${endpoint} → ${r.status}: ${(snippet ?? "").slice(0, 300)}`);
    }
    return r.data;
  }

  return {
    request,
    get: (endpoint, opts = {}) => send("GET", endpoint, opts),
    post: (endpoint, body, opts = {}) => send("POST", endpoint, { ...opts, body }),
    put: (endpoint, body, opts = {}) => send("PUT", endpoint, { ...opts, body }),
    patch: (endpoint, body, opts = {}) => send("PATCH", endpoint, { ...opts, body }),
    delete: (endpoint, opts = {}) => send("DELETE", endpoint, opts),
  };
}
