// Google Ads — the integration whose plumbing used to leak into every app.
//
// The Google Ads API needs more than an OAuth token: a developer token and a
// login-customer-id that the OAuth flow never hands back. Clawnify solves this
// with *managed actions* — the credentials worker runs the GAQL query through a
// backend that already holds the developer token, so app code needs none. That
// managed path is the default whenever a broker is present.
//
// A direct-REST backend (your own developer token from env) is kept purely as a
// local-dev fallback so the descriptor can run standalone. Both backends
// normalize into the same flat `GoogleAdsRow[]`, so the client surface — and
// therefore app code — is identical regardless of which one runs.
//
// The action identifiers below are broker-resolved and stay inside this file;
// they are never part of app code or surfaced to agents.

import type { AccessContext, ConnectionDescriptor } from "../types";

const SEARCH_STREAM = "GOOGLEADS_SEARCH_STREAM_GAQL";
const LIST_CUSTOMERS = "GOOGLEADS_LIST_ACCESSIBLE_CUSTOMERS";
const DEFAULT_VERSION = "v21";

export interface GoogleAdsRow {
  customer?: {
    id?: string;
    descriptiveName?: string;
    descriptive_name?: string;
    currencyCode?: string;
    currency_code?: string;
    manager?: boolean;
  };
  segments?: { date?: string };
  metrics?: Record<string, unknown>;
}

export interface GoogleAdsClient {
  /**
   * Run a GAQL query and get back flattened result rows. In managed mode the
   * connection targets its single configured customer and `customerId` is
   * ignored; in direct mode `customerId` selects which account to query.
   */
  query(gaql: string, opts?: { customerId?: string }): Promise<GoogleAdsRow[]>;
  /** Accessible customer ids (digits only). Empty when none are reachable. */
  listCustomerIds(): Promise<string[]>;
  /**
   * True when this client speaks to a single managed customer. Apps use it to
   * decide whether to enumerate accounts or surface the one configured account.
   */
  readonly singleCustomer: boolean;
}

// ── Response parsing (tolerant of every searchStream shape we've seen) ────────

function unwrap(data: unknown): any {
  if (typeof data === "string") {
    try {
      return JSON.parse(data);
    } catch {
      return data;
    }
  }
  return data;
}

function resultRows(data: unknown): GoogleAdsRow[] {
  const d = unwrap(data);
  if (!d) return [];
  if (Array.isArray(d)) {
    if (d.length && (d[0]?.results || d[0]?.result)) return d.flatMap((b: any) => b.results ?? b.result ?? []);
    return d as GoogleAdsRow[];
  }
  if (Array.isArray(d.results)) return d.results;
  if (d.data) return resultRows(d.data);
  if (d.response) return resultRows(d.response);
  return [];
}

function client(ctx: AccessContext): GoogleAdsClient {
  const version = ctx.env.GOOGLEADS_API_VERSION || DEFAULT_VERSION;
  const developerToken = ctx.env.GOOGLEADS_DEVELOPER_TOKEN;
  const loginCustomerId = (ctx.env.GOOGLEADS_LOGIN_CUSTOMER_ID ?? "").replace(/-/g, "");
  // Managed when a broker is available; direct only as a local-dev fallback,
  // and only if we actually have a developer token to authenticate with.
  const managed = ctx.managed;

  async function directHeaders(): Promise<Record<string, string>> {
    const token = await ctx.token();
    if (!token || !developerToken) throw new Error("Google Ads is not connected");
    const h: Record<string, string> = {
      Authorization: `Bearer ${token}`,
      "developer-token": developerToken,
      "Content-Type": "application/json",
    };
    if (loginCustomerId) h["login-customer-id"] = loginCustomerId;
    return h;
  }

  return {
    singleCustomer: managed,

    async query(gaql, opts = {}) {
      if (managed) return resultRows(await ctx.run(SEARCH_STREAM, { query: gaql }));
      const cid = (opts.customerId ?? "").replace(/\D/g, "");
      const res = await fetch(
        `https://googleads.googleapis.com/${version}/customers/${cid}/googleAds:searchStream`,
        { method: "POST", headers: await directHeaders(), body: JSON.stringify({ query: gaql }) },
      );
      const data = (await res.json()) as any;
      if (!res.ok) {
        const msg = Array.isArray(data) ? data[0]?.error?.message : data?.error?.message;
        throw new Error(msg ?? `Google Ads API error ${res.status}`);
      }
      return resultRows(data);
    },

    async listCustomerIds() {
      if (managed) {
        const data = unwrap(await ctx.run(LIST_CUSTOMERS, {}));
        const names: unknown =
          data?.resourceNames ?? data?.resource_names ?? data?.data?.resourceNames ?? (Array.isArray(data) ? data : []);
        return ((names as string[]) ?? [])
          .map((rn) => String(rn).split("/")[1] ?? String(rn))
          .map((s) => s.replace(/\D/g, ""))
          .filter(Boolean);
      }
      const res = await fetch(
        `https://googleads.googleapis.com/${version}/customers:listAccessibleCustomers`,
        { headers: await directHeaders() },
      );
      const data = (await res.json()) as any;
      if (!res.ok) throw new Error(data?.error?.message ?? `Google Ads API error ${res.status}`);
      return ((data.resourceNames ?? []) as string[]).map((rn) => rn.split("/")[1]);
    },
  };
}

export const googleads: ConnectionDescriptor<GoogleAdsClient> = {
  service: "googleads",
  label: "Google Ads",
  kind: "managed",
  accessor: `connect("googleads").query("SELECT customer.id FROM customer")`,
  client,
};
