// Proxy config — the slim, bundle-safe slice of the registry the generic proxy
// needs (docs §17.3: "Where the API is + how auth attaches" is the registry's
// concern). Just three non-secret fields per provider: how its API base URL is
// built, the header template auth attaches through, and the auth mode (which
// picks the default header when a provider declares none).
//
// The full registry.gen.json also carries provisioning config (token URLs,
// scopes, refresh recipes) that is server-side only and must never reach an app
// bundle. proxy.gen.json is generated alongside it (import-providers.mjs) with
// only these fields, so importing it here is safe to bundle into apps.

import proxyMap from "../proxy.gen.json";
import type { AuthMode } from "./definition";

/** What the generic proxy reads to build a request for a provider. */
export interface ProxyConfig {
  /** providers.yaml proxy.base_url. May contain `${connectionConfig.x}` templates. */
  baseUrl?: string;
  /** Header templates (e.g. `{ authorization: "AccessKey ${apiKey}" }`). Absent ⇒ default by authMode. */
  proxyHeaders?: Record<string, string>;
  /** Picks the default auth header when proxyHeaders is absent (Bearer for OAuth). */
  authMode: AuthMode;
  /**
   * Default values for `${connectionConfig.x}` templates, from providers.yaml
   * `default_value` (e.g. Bird `subdomain: "api"`). The proxy fills a template
   * var from these only when no per-call/env value is given.
   */
  connectionConfigDefaults?: Record<string, string>;
}

interface RawProxyConfig extends ProxyConfig {
  /** Provider this entry inherits from (already resolved at generation time). */
  aliasOf?: string;
}

const MAP = proxyMap as Record<string, RawProxyConfig>;

/**
 * Proxy config for a provider id, or undefined if the registry doesn't cover it.
 * Service ids here are the registry/own-tier ids (`bird`, `wordpress`, …) —
 * the same id passed to `connect()` for an own-tier integration.
 */
export function proxyConfig(service: string): ProxyConfig | undefined {
  const entry = MAP[service];
  if (!entry) return undefined;
  return {
    baseUrl: entry.baseUrl,
    proxyHeaders: entry.proxyHeaders,
    authMode: entry.authMode,
    connectionConfigDefaults: entry.connectionConfigDefaults,
  };
}
