// Maintainer — a credential source behind connect(). The seam that makes the
// connections layer broker-agnostic and scalable (docs §13): each maintainer is
// one adapter implementing a way to yield an unmasked credential OR execute on
// our behalf. Integrations are routed to a maintainer by approval difficulty —
// can't-approve → an execute maintainer (ride a broker's pre-approved app);
// can-access → a token maintainer (raw creds in our vault, direct API).
//
// Capabilities are explicit because maintainers are NOT uniform:
//   • token   — returns a usable raw access token (own / nango / arcade)
//   • execute — runs a named provider action server-side, creds never exposed
//               (composio managed — masked tokens, so execute-only)
//   • search  — semantic action discovery over the broker catalog (§16)
//
// connect() resolves token-first (sovereignty), falling back to execute. The
// app never learns which maintainer served it.

export type MaintainerCapability = "token" | "execute" | "search";

export interface ExecuteResult {
  data: unknown;
  error: string | null;
  successful: boolean;
}

/**
 * One action from a maintainer's catalog (search result). `slug` feeds
 * execute()/run(); `inputSchema` is the JSON Schema for the request body.
 * Returned best-first. Canonical home is here (an integration concept);
 * @clawnify/connections re-exports it. See docs §16.
 */
export interface ActionMatch {
  /** Toolkit/integration slug. */
  service: string;
  /** Action slug — pass to run(slug, body). */
  slug: string;
  name: string;
  description: string;
  /** JSON Schema for the request body, or null if the catalog omits it. */
  inputSchema: Record<string, unknown> | null;
}

export interface Maintainer {
  /** Stable id: "composio" | "own" | "nango" | "arcade" | … */
  readonly name: string;
  readonly capabilities: readonly MaintainerCapability[];

  /** Raw access token for a connected service, or null if this maintainer can't yield one. */
  getToken?(service: string, orgId: string): Promise<string | null>;

  /** Run a named provider action; credentials stay inside the maintainer. */
  execute?(
    service: string,
    action: string,
    args: Record<string, unknown>,
    orgId: string,
  ): Promise<ExecuteResult>;

  /** Discover actions (+ input schemas) from the maintainer's catalog. */
  search?(query: string, service: string | null, limit: number): Promise<ActionMatch[]>;

  /** Services this maintainer currently holds a connection for, scoped to the org. */
  listConnected?(orgId: string): Promise<string[]>;
}

/** Has this maintainer been wired to yield raw tokens? */
export function canToken(m: Maintainer): m is Maintainer & Required<Pick<Maintainer, "getToken">> {
  return m.capabilities.includes("token") && typeof m.getToken === "function";
}

/** Can this maintainer execute provider actions on our behalf? */
export function canExecute(m: Maintainer): m is Maintainer & Required<Pick<Maintainer, "execute">> {
  return m.capabilities.includes("execute") && typeof m.execute === "function";
}
