/**
 * @clawnify/connections — the accessor SDK.
 *
 * Three calls cover every credential an app needs:
 *
 *   connect("googleads", env)        → a typed client (oauth or managed alike)
 *   secret("OPENROUTER_API_KEY", env)→ an injected provider key / secret
 *   describe(env, orgId, requires)   → agent-legible "what's wired" snapshot
 *
 * App code is identical whether a connection is managed or self-served, OAuth or
 * API key, dynamic or static. The broker that actually holds a credential lives
 * behind the Clawnify credentials binding and is never named here — `describe()`
 * speaks only in capabilities (`oauth`/`managed`/`key`/`secret`).
 */

import {
  getDescriptor,
  allDescriptors,
  type ServiceClients,
  type ConnectionDescriptor,
  type ConnectionKind,
  type AccessContext,
  type ActionMatch,
} from "@clawnify/integrations";

import { makeProxyClient, type ProxyClient } from "./proxy";

// Re-export the descriptor layer so consumers get client types (MetaAdsClient,
// GoogleAdsRow, …) and descriptor types from one import.
export * from "@clawnify/integrations";
export {
  makeProxyClient,
  resolveRequest,
  type ProxyClient,
  type ProxyRequestOpts,
  type ProxyResult,
  type HttpMethod,
} from "./proxy";

/**
 * The credentials broker RPC contract — the Clawnify `CREDENTIALS` service
 * binding injected into every app. These method names are Clawnify-internal;
 * the provider behind them (managed or self-configured) is not part of the
 * contract.
 */
export interface CredentialBinding {
  getToken(service: string, orgId: string): Promise<string | null>;
  executeTool(
    service: string,
    toolSlug: string,
    args: Record<string, unknown>,
    orgId: string,
  ): Promise<{ data: unknown; error: string | null; successful: boolean }>;
  listConnected(orgId: string): Promise<string[]>;
  searchActions(query: string, service: string | null, limit: number): Promise<ActionMatch[]>;
}

// ActionMatch is defined in @clawnify/integrations (canonical home) and
// re-exported via `export * from "@clawnify/integrations"` above. See docs §16.

/** The slice of a worker's `env` the SDK reads. */
export interface ConnectionsEnv {
  /** The in-process credentials binding. Present in deployed apps. */
  CREDENTIALS?: CredentialBinding;
  /** The org the app is serving, injected by the Clawnify builder. */
  CLAWNIFY_ORG_ID?: string;
  /**
   * A Clawnify token: either the OAuth bearer `clawnify login` holds, or a
   * long-lived org service token (clw_…). When set and no in-process
   * CREDENTIALS binding exists, the SDK resolves connections over HTTP via the
   * Clawnify API — so local `pnpm dev` / scripts reach real org connections
   * with no per-service secrets. With an OAuth bearer spanning several orgs,
   * CLAWNIFY_ORG_ID picks one; a service token fixes the org itself.
   */
  CLAWNIFY_TOKEN?: string;
  /** Override the Clawnify API base for the HTTP binding (defaults to prod). */
  CLAWNIFY_API_URL?: string;
  /** Injected provider keys / secrets / local-dev token fallbacks. */
  [key: string]: unknown;
}

const DEFAULT_API_BASE = "https://provision.clawnify.com";

/**
 * An HTTP-backed {@link CredentialBinding} for environments without the
 * in-process binding (local `pnpm dev`, scripts, Claude Code).
 *
 * `token` is either a Clawnify OAuth bearer (the session `clawnify login`
 * holds) or a long-lived org service token (clw_…). With an OAuth bearer that
 * belongs to several orgs, pass `orgId` to target one (sent as `x-org-id`);
 * with a service token the org is fixed and `orgId` is ignored. Managed
 * credentials stay server-side — only `getToken` returns a bearer.
 */
export function clawnifyBinding(opts: { token: string; baseUrl?: string; orgId?: string }): CredentialBinding {
  const base = (opts.baseUrl ?? DEFAULT_API_BASE).replace(/\/+$/, "");
  const headers: Record<string, string> = {
    Authorization: `Bearer ${opts.token}`,
    "Content-Type": "application/json",
    ...(opts.orgId ? { "x-org-id": opts.orgId } : {}),
  };
  return {
    async getToken(service) {
      const res = await fetch(`${base}/v1/connections/token`, {
        method: "POST",
        headers,
        body: JSON.stringify({ service }),
      });
      if (!res.ok) return null;
      const j = (await res.json()) as { token?: string | null };
      return j.token ?? null;
    },
    async executeTool(service, toolSlug, args) {
      const res = await fetch(`${base}/v1/connections/execute`, {
        method: "POST",
        headers,
        body: JSON.stringify({ service, action: toolSlug, args }),
      });
      const j = (await res.json().catch(() => ({}))) as {
        data?: unknown;
        error?: string | null;
        successful?: boolean;
      };
      if (!res.ok) return { data: null, error: j.error ?? `connections ${res.status}`, successful: false };
      return { data: j.data ?? null, error: j.error ?? null, successful: j.successful ?? true };
    },
    async listConnected() {
      const res = await fetch(`${base}/v1/connections/connected`, { headers });
      if (!res.ok) return [];
      const j = (await res.json()) as { services?: string[] };
      return j.services ?? [];
    },
    async searchActions(query, service, limit) {
      const res = await fetch(`${base}/v1/connections/actions`, {
        method: "POST",
        headers,
        body: JSON.stringify({ query, service, limit }),
      });
      if (!res.ok) return [];
      const j = (await res.json()) as { actions?: ActionMatch[] };
      return j.actions ?? [];
    },
  };
}

/**
 * The binding to use this request: the in-process one if present, else an HTTP
 * binding built from CLAWNIFY_TOKEN. `remote` binding resolves the org from the
 * token, so it works without a local org id.
 */
function resolveBinding(env: ConnectionsEnv): { binding?: CredentialBinding; remote: boolean } {
  if (env.CREDENTIALS) return { binding: env.CREDENTIALS, remote: false };
  const token = typeof env.CLAWNIFY_TOKEN === "string" ? env.CLAWNIFY_TOKEN : "";
  if (token) {
    const baseUrl = typeof env.CLAWNIFY_API_URL === "string" ? env.CLAWNIFY_API_URL : undefined;
    const orgId = typeof env.CLAWNIFY_ORG_ID === "string" ? env.CLAWNIFY_ORG_ID : undefined;
    return { binding: clawnifyBinding({ token, baseUrl, orgId }), remote: true };
  }
  return { remote: false };
}

function resolveOrg(env: ConnectionsEnv, orgId?: string): string | null {
  return orgId ?? env.CLAWNIFY_ORG_ID ?? null;
}

function buildContext(service: string, env: ConnectionsEnv, orgId: string | null): AccessContext {
  const { binding, remote } = resolveBinding(env);
  // A remote binding derives the org from the token, so it works without a
  // local org id; an in-process binding needs one.
  const canBroker = !!binding && (remote || !!orgId);
  return {
    orgId,
    managed: canBroker,
    env: env as Record<string, string | undefined>,
    async token() {
      if (binding && canBroker) {
        try {
          return await binding.getToken(service, orgId ?? "");
        } catch {
          return null;
        }
      }
      // Local-dev fallback: a bare token in env, e.g. METAADS_BEARER_TOKEN.
      const up = service.toUpperCase();
      const local = env[`${up}_BEARER_TOKEN`] ?? env[`${up}_ACCESS_TOKEN`];
      return typeof local === "string" ? local : null;
    },
    async run(action, args = {}) {
      if (!binding || !canBroker) {
        throw new Error(`"${service}" needs the Clawnify credentials binding or CLAWNIFY_TOKEN`);
      }
      const r = await binding.executeTool(service, action, args, orgId ?? "");
      if (!r.successful) throw new Error(r.error ?? `${service} action "${action}" failed`);
      return r.data;
    },
  };
}

/**
 * Low-level client returned for any integration without a bespoke descriptor.
 * Every integration supports these operations, so a new dashboard integration
 * is usable immediately — no descriptor, no package release.
 *
 * `token()`/`run()` cover any maintainer. `get/post/…` are the registry-driven
 * generic proxy (docs §17): for an own-tier provider in the registry they call
 * its real API directly with the injected credential — no per-integration code.
 * On a managed/Composio-only service (not in the proxy registry, or no
 * injectable credential) the proxy verbs throw and point you at `run()`.
 */
export interface GenericClient extends ProxyClient {
  /** Current access token (OAuth / API key) for this integration. */
  token(): Promise<string | null>;
  /** Run a managed action scoped to the org; returns its data, throws on failure. */
  run(action: string, args?: Record<string, unknown>): Promise<unknown>;
}

/** A proxy client that always throws — used when a service isn't in the proxy registry. */
function unsupportedProxy(service: string): ProxyClient {
  const fail = async (): Promise<never> => {
    throw new Error(
      `"${service}" is not a registry-backed own-tier provider; the generic proxy can't reach it. ` +
        `Use connect("${service}").run(action, body) (find the action via searchActions).`,
    );
  };
  return { request: fail, get: fail, post: fail, put: fail, patch: fail, delete: fail };
}

/**
 * Get a client for an integration.
 *
 * - Registered integrations return their typed client — `connect("googleads",
 *   env)` is a GoogleAdsClient, no casting.
 * - Any other (e.g. a toolkit just added in the dashboard) returns a
 *   {@link GenericClient} with `token()` + `run()`. The registry is an
 *   ergonomics layer, never a gate: functionality never depends on a release.
 *
 * @throws only when the service is a known key/secret — read those with secret().
 */
export function connect<K extends keyof ServiceClients>(service: K, env: ConnectionsEnv, orgId?: string): ServiceClients[K];
export function connect(service: string, env: ConnectionsEnv, orgId?: string): GenericClient;
export function connect(service: string, env: ConnectionsEnv, orgId?: string): unknown {
  const ctx = buildContext(service, env, resolveOrg(env, orgId));
  const desc = getDescriptor(service);
  if (desc?.client) return desc.client(ctx);
  if (desc && (desc.kind === "key" || desc.kind === "secret")) {
    throw new Error(`"${service}" is a ${desc.kind}; read it with secret("${desc.envName ?? service}")`);
  }
  const proxy = makeProxyClient(service, ctx) ?? unsupportedProxy(service);
  return { token: ctx.token, run: ctx.run, ...proxy } satisfies GenericClient;
}

/**
 * Search the broker action catalog for the right action to call, returned
 * best-first with each action's input schema (the request body). The default
 * way to use the long tail of integrations: search → read `inputSchema` →
 * `connect(service).run(slug, body)`, with no per-integration package code.
 *
 * Broker-agnostic — the active broker's own search backs it (Composio today).
 * `[0]` is the canonical match. Catalog metadata, so it works without an org
 * id; needs the in-process CREDENTIALS binding or CLAWNIFY_TOKEN. See docs §16.
 *
 * @example
 *   const [best] = await searchActions("post a message to slack", env);
 *   if (best) await connect(best.service, env).run(best.slug, { channel, text });
 */
export async function searchActions(
  query: string,
  env: ConnectionsEnv,
  opts: { service?: string; limit?: number } = {},
): Promise<ActionMatch[]> {
  const { binding } = resolveBinding(env);
  if (!binding) return [];
  try {
    return await binding.searchActions(query, opts.service ?? null, opts.limit ?? 10);
  } catch {
    return [];
  }
}

/** Read an injected provider key / secret env var. Returns null when absent. */
export function secret(name: string, env: ConnectionsEnv): string | null {
  const v = env[name];
  return typeof v === "string" && v.length > 0 ? v : null;
}

/** True when a usable credential exists for this service right now. */
export async function isConnected(service: string, env: ConnectionsEnv, orgId?: string): Promise<boolean> {
  const desc = getDescriptor(service);
  if (!desc) return false;
  const org = resolveOrg(env, orgId);
  if (desc.kind === "key" || desc.kind === "secret") {
    return !!secret(desc.envName ?? service, env);
  }
  const { binding, remote } = resolveBinding(env);
  if (binding && (remote || org)) {
    try {
      if ((await binding.listConnected(org ?? "")).includes(service)) return true;
    } catch {
      /* fall through to token probe */
    }
  }
  return !!(await buildContext(service, env, org).token());
}

/** One entry in clawnify.json's `requires` block. */
export type RequireSpec =
  | { service: string; as: "integration" }
  | { name: string; as: "key" | "secret" };

/** Per-capability readiness, written for an agent to read before wiring code. */
export interface DescribeEntry {
  /** Service id (integrations) or env var name (keys/secrets). */
  id: string;
  label: string;
  kind: ConnectionKind;
  /** Whether a credential is present for this capability. */
  connected: boolean;
  /** Whether app code can use it right now (same as connected today). */
  ready: boolean;
  /** One-line snippet showing how to access it in app code. */
  accessor: string;
  /** What to do when it isn't ready — always dashboard-driven. */
  hint?: string;
}

/**
 * Report what's wired for an org. Pass the app's `requires` to report exactly
 * those capabilities (the agent-facing case); omit it to report every known
 * integration's status for the org.
 *
 * Never names the underlying broker — only `kind` and readiness.
 */
export async function describe(
  env: ConnectionsEnv,
  orgId?: string,
  requires?: RequireSpec[],
): Promise<DescribeEntry[]> {
  const org = resolveOrg(env, orgId);

  // Normalize the work list. A required service with no descriptor is reported
  // generically (still fully usable via connect()'s GenericClient) — the
  // registry enriches, it never gates.
  type Item = { id: string; label: string; kind: ConnectionKind; accessor: string; isKey: boolean };
  const fromDescriptor = (d: ConnectionDescriptor): Item => {
    const isKey = d.kind === "key" || d.kind === "secret";
    return { id: isKey ? d.envName ?? d.service : d.service, label: d.label, kind: d.kind, accessor: d.accessor, isKey };
  };

  let items: Item[];
  if (requires?.length) {
    items = requires.map((r) => {
      if ("name" in r) {
        const d = getDescriptor(r.name);
        return d ? fromDescriptor(d) : { id: r.name, label: r.name, kind: r.as, accessor: `secret("${r.name}")`, isKey: true };
      }
      const d = getDescriptor(r.service);
      // Unknown integration: kind is genuinely unknown without a descriptor;
      // "managed" is the broadest accessor (token() + run() both work).
      return d ? fromDescriptor(d) : { id: r.service, label: r.service, kind: "managed" as ConnectionKind, accessor: `connect("${r.service}")`, isKey: false };
    });
  } else {
    items = allDescriptors().map(fromDescriptor);
  }

  // One broker round-trip for all integration kinds.
  let connectedList: string[] = [];
  const { binding, remote } = resolveBinding(env);
  if (binding && (remote || org) && items.some((i) => !i.isKey)) {
    try {
      connectedList = await binding.listConnected(org ?? "");
    } catch {
      /* leave empty — everything reports not-connected */
    }
  }

  return items.map((i) => {
    const has = i.isKey ? !!secret(i.id, env) : connectedList.includes(i.id);
    const hint = has
      ? undefined
      : i.isKey
        ? `Add ${i.id} in the dashboard → API Keys / Environment Variables.`
        : `Connect ${i.label} in the dashboard → Integrations.`;
    return { id: i.id, label: i.label, kind: i.kind, connected: has, ready: has, accessor: i.accessor, hint };
  });
}
