// OpenRouter — a plain provider API key. No client surface: app code reads the
// injected secret directly with `secret("OPENROUTER_API_KEY")` and calls the
// OpenRouter HTTP API itself. The descriptor exists so describe() can report the
// key's name, readiness, and accessor to an agent before it writes code.

import type { ConnectionDescriptor } from "../types";

export const openrouter: ConnectionDescriptor = {
  service: "openrouter",
  label: "OpenRouter",
  kind: "key",
  envName: "OPENROUTER_API_KEY",
  accessor: `secret("OPENROUTER_API_KEY")`,
};
