// Meta Ads — canonical reporting methods over whatever credential maintainer is
// wired. Today the maintainer is Composio (masked raw tokens → we go through its
// managed tool execution: METAADS_GET_*). The Composio slugs live *inside* this
// descriptor and never leak to app code (docs §16); when a raw-token maintainer
// (own/Nango) lands, only these method bodies change — the app keeps calling the
// same semantic methods (docs §14). Insight rows come back in Meta's native shape,
// so consumers parse actions/action_values exactly as the Graph API returns them.

import type { AccessContext, ConnectionDescriptor } from "../types";

export interface MetaAction {
  action_type: string;
  value: string;
}

/** A Meta Insights row — native Graph API shape (one per object, or per day). */
export interface MetaInsightRow {
  date_start?: string;
  date_stop?: string;
  spend?: string;
  impressions?: string;
  clicks?: string;
  actions?: MetaAction[];
  action_values?: MetaAction[];
}

export interface MetaAdAccount {
  id: string;
  account_id?: string;
  name?: string;
  currency?: string;
  account_status?: number;
}

export interface MetaInsightsOptions {
  /** account | campaign | adset | ad. Default "account". */
  level?: string;
  /** Metric fields. Default spend/impressions/clicks/actions/action_values. */
  fields?: string[];
  /** Explicit date window (YYYY-MM-DD). Takes precedence over datePreset. */
  since?: string;
  until?: string;
  /** Predefined window (e.g. "last_30d") when no since/until. */
  datePreset?: string;
  /**
   * Breakdown granularity, passed to Graph's `time_increment`: `1` (daily),
   * `"monthly"`, or `"all_days"` (the default — one aggregate row). Use `1` to
   * get a per-day series for charts.
   */
  timeIncrement?: number | string;
}

export interface MetaAdsClient {
  /** Ad accounts the connection can access. */
  adAccounts(fields?: string): Promise<MetaAdAccount[]>;
  /** Insights rows for an object (ad account / campaign / ad set / ad). */
  insights(objectId: string, opts?: MetaInsightsOptions): Promise<MetaInsightRow[]>;
  /** Fetch a single object's fields (e.g. ["name","currency"]). */
  object(objectId: string, fields: string[]): Promise<Record<string, any>>;
}

const DEFAULT_INSIGHT_FIELDS = ["spend", "impressions", "clicks", "actions", "action_values"];

function client(ctx: AccessContext): MetaAdsClient {
  return {
    async adAccounts(fields = "id,name,currency,account_status") {
      const d = (await ctx.run("METAADS_GET_AD_ACCOUNTS", { fields, limit: 100 })) as
        | { data?: MetaAdAccount[] }
        | undefined;
      return d?.data ?? [];
    },

    async insights(objectId, opts = {}) {
      const args: Record<string, unknown> = {
        object_id: objectId,
        level: opts.level ?? "account",
        fields: opts.fields ?? DEFAULT_INSIGHT_FIELDS,
      };
      if (opts.since && opts.until) args.time_range = { since: opts.since, until: opts.until };
      else args.date_preset = opts.datePreset ?? "last_30d";
      if (opts.timeIncrement != null) args.time_increment = opts.timeIncrement;
      const d = (await ctx.run("METAADS_GET_INSIGHTS", args)) as { data?: MetaInsightRow[] } | undefined;
      return d?.data ?? [];
    },

    async object(objectId, fields) {
      // GET_OBJECT returns the object directly (no { data } wrapper).
      const d = (await ctx.run("METAADS_GET_OBJECT", { object_id: objectId, fields })) as
        | Record<string, any>
        | undefined;
      return d ?? {};
    },
  };
}

export const metaads: ConnectionDescriptor<MetaAdsClient> = {
  service: "metaads",
  label: "Meta Ads",
  kind: "oauth",
  accessor: `connect("metaads").adAccounts("id,name,currency")`,
  client,
};
