import type { ConnectionDescriptor } from "./types";
import { metaads, type MetaAdsClient } from "./descriptors/metaads";
import { googleads, type GoogleAdsClient } from "./descriptors/googleads";
import { openrouter } from "./descriptors/openrouter";

/** Every known integration, keyed by canonical service id. */
export const DESCRIPTORS = { metaads, googleads, openrouter } as const;

export type ServiceId = keyof typeof DESCRIPTORS;

/**
 * Map of service id → its typed client. Only integrations that expose a client
 * (oauth/managed) appear here; key/secret integrations are read via secret().
 * connect() is generic over this map, so connect("googleads") is typed as a
 * GoogleAdsClient with no casting at the call site.
 */
export interface ServiceClients {
  metaads: MetaAdsClient;
  googleads: GoogleAdsClient;
}

export function getDescriptor(service: string): ConnectionDescriptor | undefined {
  return (DESCRIPTORS as Record<string, ConnectionDescriptor>)[service];
}

export function allDescriptors(): ConnectionDescriptor[] {
  return Object.values(DESCRIPTORS) as ConnectionDescriptor[];
}
